import{_ as e,o as l,c as i,ae as o}from"./chunks/framework.BEtfQoF7.js";const p=JSON.parse('{"title":"JetBrains IDE","description":"IntelliJ, PyCharm, WebStorm 등 JetBrains IDE에서 Claude Code를 사용하세요.","frontmatter":{"title":"JetBrains IDE","description":"IntelliJ, PyCharm, WebStorm 등 JetBrains IDE에서 Claude Code를 사용하세요."},"headers":[],"relativePath":"jetbrains.md","filePath":"jetbrains.md","lastUpdated":1776205703000}'),t={name:"jetbrains.md"};function d(r,a,s,n,c,u){return l(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="jetbrains-ide" tabindex="-1">JetBrains IDE <a class="header-anchor" href="#jetbrains-ide" aria-label="Permalink to &quot;JetBrains IDE&quot;">​</a></h1><p>Claude Code는 전용 플러그인을 통해 JetBrains IDE와 통합되어 인터랙티브 diff 보기, 선택 컨텍스트 공유 등의 기능을 제공합니다.</p><h2 id="지원되는-ide" tabindex="-1">지원되는 IDE <a class="header-anchor" href="#지원되는-ide" aria-label="Permalink to &quot;지원되는 IDE&quot;">​</a></h2><p>Claude Code 플러그인은 다음을 포함한 대부분의 JetBrains IDE에서 작동합니다:</p><ul><li>IntelliJ IDEA</li><li>PyCharm</li><li>Android Studio</li><li>WebStorm</li><li>PhpStorm</li><li>GoLand</li></ul><h2 id="기능" tabindex="-1">기능 <a class="header-anchor" href="#기능" aria-label="Permalink to &quot;기능&quot;">​</a></h2><ul><li><strong>빠른 실행</strong>: <code>Cmd+Esc</code> (Mac) 또는 <code>Ctrl+Esc</code> (Windows/Linux)를 사용하여 편집기에서 직접 Claude Code를 열거나, UI의 Claude Code 버튼을 클릭합니다</li><li><strong>Diff 보기</strong>: 코드 변경 사항을 터미널 대신 IDE diff 뷰어에서 직접 표시할 수 있습니다</li><li><strong>선택 컨텍스트</strong>: IDE에서 현재 선택/탭이 자동으로 Claude Code와 공유됩니다</li><li><strong>파일 참조 단축키</strong>: <code>Cmd+Option+K</code> (Mac) 또는 <code>Alt+Ctrl+K</code> (Linux/Windows)를 사용하여 파일 참조를 삽입합니다 (예: @File#L1-99)</li><li><strong>진단 공유</strong>: IDE의 진단 오류(lint, 구문 등)가 작업 중 자동으로 Claude와 공유됩니다</li></ul><h2 id="설치" tabindex="-1">설치 <a class="header-anchor" href="#설치" aria-label="Permalink to &quot;설치&quot;">​</a></h2><h3 id="마켓플레이스-설치" tabindex="-1">마켓플레이스 설치 <a class="header-anchor" href="#마켓플레이스-설치" aria-label="Permalink to &quot;마켓플레이스 설치&quot;">​</a></h3><p>JetBrains 마켓플레이스에서 <a href="https://plugins.jetbrains.com/plugin/27310-claude-code-beta-" target="_blank" rel="noreferrer">Claude Code 플러그인</a>을 찾아 설치하고 IDE를 재시작하세요.</p><p>아직 Claude Code를 설치하지 않았다면 설치 방법은 <a href="/claude-code-docs-ko/quickstart.html">빠른 시작 가이드</a>를 참조하세요.</p><div class="info custom-block"><p class="custom-block-title">참고</p><p>플러그인을 설치한 후 적용하려면 IDE를 완전히 재시작해야 할 수 있습니다.</p></div><h2 id="사용법" tabindex="-1">사용법 <a class="header-anchor" href="#사용법" aria-label="Permalink to &quot;사용법&quot;">​</a></h2><h3 id="ide에서-사용" tabindex="-1">IDE에서 사용 <a class="header-anchor" href="#ide에서-사용" aria-label="Permalink to &quot;IDE에서 사용&quot;">​</a></h3><p>IDE의 통합 터미널에서 <code>claude</code>를 실행하면 모든 통합 기능이 활성화됩니다.</p><h3 id="외부-터미널에서-사용" tabindex="-1">외부 터미널에서 사용 <a class="header-anchor" href="#외부-터미널에서-사용" aria-label="Permalink to &quot;외부 터미널에서 사용&quot;">​</a></h3><p>외부 터미널에서 <code>/ide</code> 명령을 사용하여 Claude Code를 JetBrains IDE에 연결하고 모든 기능을 활성화합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ide</span></span></code></pre></div><p>Claude가 IDE와 동일한 파일에 접근하려면 IDE 프로젝트 루트와 동일한 디렉토리에서 Claude Code를 시작하세요.</p><h2 id="설정" tabindex="-1">설정 <a class="header-anchor" href="#설정" aria-label="Permalink to &quot;설정&quot;">​</a></h2><h3 id="claude-code-설정" tabindex="-1">Claude Code 설정 <a class="header-anchor" href="#claude-code-설정" aria-label="Permalink to &quot;Claude Code 설정&quot;">​</a></h3><p>Claude Code 설정을 통해 IDE 통합을 구성합니다:</p><ol><li><code>claude</code>를 실행합니다</li><li><code>/config</code> 명령을 입력합니다</li><li>diff 도구를 <code>auto</code>로 설정하여 자동 IDE 감지를 활성화합니다</li></ol><h3 id="플러그인-설정" tabindex="-1">플러그인 설정 <a class="header-anchor" href="#플러그인-설정" aria-label="Permalink to &quot;플러그인 설정&quot;">​</a></h3><p>**Settings → Tools → Claude Code [Beta]**로 이동하여 Claude Code 플러그인을 구성합니다:</p><h4 id="일반-설정" tabindex="-1">일반 설정 <a class="header-anchor" href="#일반-설정" aria-label="Permalink to &quot;일반 설정&quot;">​</a></h4><ul><li><strong>Claude command</strong>: Claude를 실행할 커스텀 명령을 지정합니다 (예: <code>claude</code>, <code>/usr/local/bin/claude</code> 또는 <code>npx @anthropic-ai/claude-code</code>)</li><li><strong>Suppress notification for Claude command not found</strong>: Claude 명령을 찾을 수 없다는 알림을 건너뜁니다</li><li><strong>Enable using Option+Enter for multi-line prompts</strong> (macOS 전용): 활성화하면 Option+Enter가 Claude Code 프롬프트에서 새 줄을 삽입합니다. Option 키가 예기치 않게 캡처되는 문제가 발생하면 비활성화하세요 (터미널 재시작 필요)</li><li><strong>Enable automatic updates</strong>: 플러그인 업데이트를 자동으로 확인하고 설치합니다 (재시작 시 적용)</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>WSL 사용자의 경우: Claude 명령으로 <code>wsl -d Ubuntu -- bash -lic &quot;claude&quot;</code>를 설정하세요 (<code>Ubuntu</code>를 WSL 배포판 이름으로 교체)</p></div><h4 id="esc-키-설정" tabindex="-1">ESC 키 설정 <a class="header-anchor" href="#esc-키-설정" aria-label="Permalink to &quot;ESC 키 설정&quot;">​</a></h4><p>JetBrains 터미널에서 ESC 키가 Claude Code 작업을 중단하지 않는 경우:</p><ol><li><strong>Settings → Tools → Terminal</strong>로 이동합니다</li><li>다음 중 하나를 수행합니다: <ul><li>&quot;Move focus to the editor with Escape&quot; 체크를 해제하거나</li><li>&quot;Configure terminal keybindings&quot;를 클릭하고 &quot;Switch focus to Editor&quot; 단축키를 삭제합니다</li></ul></li><li>변경 사항을 적용합니다</li></ol><p>이렇게 하면 ESC 키가 Claude Code 작업을 올바르게 중단할 수 있습니다.</p><h2 id="특수-설정" tabindex="-1">특수 설정 <a class="header-anchor" href="#특수-설정" aria-label="Permalink to &quot;특수 설정&quot;">​</a></h2><h3 id="원격-개발" tabindex="-1">원격 개발 <a class="header-anchor" href="#원격-개발" aria-label="Permalink to &quot;원격 개발&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">주의</p><p>JetBrains 원격 개발을 사용할 때는 **Settings → Plugin (Host)**에서 원격 호스트에 플러그인을 설치해야 합니다.</p></div><p>플러그인은 로컬 클라이언트 머신이 아닌 원격 호스트에 설치해야 합니다.</p><h3 id="wsl-설정" tabindex="-1">WSL 설정 <a class="header-anchor" href="#wsl-설정" aria-label="Permalink to &quot;WSL 설정&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">주의</p><p>WSL 사용자는 IDE 감지가 제대로 작동하려면 추가 설정이 필요할 수 있습니다. 자세한 설정 방법은 <a href="/claude-code-docs-ko/troubleshooting.html#jetbrains-ide-not-detected-on-wsl2">WSL 문제 해결 가이드</a>를 참조하세요.</p></div><p>WSL 설정에는 다음이 필요할 수 있습니다:</p><ul><li>올바른 터미널 설정</li><li>네트워킹 모드 조정</li><li>방화벽 설정 업데이트</li></ul><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><h3 id="플러그인이-작동하지-않음" tabindex="-1">플러그인이 작동하지 않음 <a class="header-anchor" href="#플러그인이-작동하지-않음" aria-label="Permalink to &quot;플러그인이 작동하지 않음&quot;">​</a></h3><ul><li>프로젝트 루트 디렉토리에서 Claude Code를 실행하고 있는지 확인하세요</li><li>IDE 설정에서 JetBrains 플러그인이 활성화되어 있는지 확인하세요</li><li>IDE를 완전히 재시작하세요 (여러 번 해야 할 수 있습니다)</li><li>원격 개발의 경우 원격 호스트에 플러그인이 설치되어 있는지 확인하세요</li></ul><h3 id="ide가-감지되지-않음" tabindex="-1">IDE가 감지되지 않음 <a class="header-anchor" href="#ide가-감지되지-않음" aria-label="Permalink to &quot;IDE가 감지되지 않음&quot;">​</a></h3><ul><li>플러그인이 설치되고 활성화되어 있는지 확인하세요</li><li>IDE를 완전히 재시작하세요</li><li>통합 터미널에서 Claude Code를 실행하고 있는지 확인하세요</li><li>WSL 사용자의 경우 <a href="/claude-code-docs-ko/troubleshooting.html#jetbrains-ide-not-detected-on-wsl2">WSL 문제 해결 가이드</a>를 참조하세요</li></ul><h3 id="명령을-찾을-수-없음" tabindex="-1">명령을 찾을 수 없음 <a class="header-anchor" href="#명령을-찾을-수-없음" aria-label="Permalink to &quot;명령을 찾을 수 없음&quot;">​</a></h3><p>Claude 아이콘을 클릭했을 때 &quot;command not found&quot;가 표시되는 경우:</p><ol><li>Claude Code가 설치되어 있는지 확인합니다: <code>npm list -g @anthropic-ai/claude-code</code></li><li>플러그인 설정에서 Claude 명령 경로를 구성합니다</li><li>WSL 사용자의 경우 설정 섹션에서 언급된 WSL 명령 형식을 사용합니다</li></ol><h2 id="보안-고려-사항" tabindex="-1">보안 고려 사항 <a class="header-anchor" href="#보안-고려-사항" aria-label="Permalink to &quot;보안 고려 사항&quot;">​</a></h2><p>Claude Code가 자동 편집 권한이 활성화된 JetBrains IDE에서 실행될 때, IDE에 의해 자동으로 실행될 수 있는 IDE 설정 파일을 수정할 수 있습니다. 이는 자동 편집 모드에서 Claude Code를 실행하는 위험을 증가시키고 bash 실행에 대한 Claude Code의 권한 프롬프트를 우회할 수 있습니다.</p><p>JetBrains IDE에서 실행할 때 다음을 고려하세요:</p><ul><li>편집에 대해 수동 승인 모드 사용</li><li>Claude가 신뢰할 수 있는 프롬프트에서만 사용되도록 각별히 주의</li><li>Claude Code가 수정할 수 있는 파일을 인식</li></ul><p>추가 도움이 필요하면 <a href="/claude-code-docs-ko/troubleshooting.html">문제 해결 가이드</a>를 참조하세요.</p>',54)])])}const b=e(t,[["render",d]]);export{p as __pageData,b as default};
